import React, { useState, useEffect } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";
import "../App.css";

const PostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [deleting, setDeleting] = useState(false);
  const [newComment, setNewComment] = useState("");

  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteConfirmType, setDeleteConfirmType] = useState("");
  const [targetId, setTargetId] = useState("");
  const [deletingCommentId, setDeletingCommentId] = useState(null);

  // ================= FETCH POST =================
  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setPost(res.data);

        const commentsRes = await API.get(`/comments/${id}`);
        setComments(commentsRes.data);
      } catch (err) {
        setError("Post not found or error loading post");
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  // ================= DELETE POST =================
  const handleDeleteClick = () => {
    setDeleteConfirmType("post");
    setTargetId(id);
    setShowDeleteConfirm(true);
  };

  const handleDeleteConfirm = async () => {
    setDeleting(true);
    try {
      await API.delete(`/posts/${targetId}`);
      navigate("/profile");
    } catch (err) {
      setError("Failed to delete post");
    } finally {
      setDeleting(false);
      setShowDeleteConfirm(false);
    }
  };

  // ================= DELETE COMMENT =================
  const handleDeleteCommentClick = (commentId) => {
    setDeleteConfirmType("comment");
    setTargetId(commentId);
    setShowDeleteConfirm(true);
  };

  const handleDeleteCommentConfirm = async () => {
    setDeletingCommentId(targetId);
    try {
      await API.delete(`/comments/${targetId}`);
      setComments((prev) => prev.filter((c) => c._id !== targetId));
    } catch (err) {
      setError("Failed to delete comment");
    } finally {
      setDeletingCommentId(null);
      setShowDeleteConfirm(false);
    }
  };

  const handleDeleteCancel = () => {
    setShowDeleteConfirm(false);
    setDeleteConfirmType("");
    setTargetId("");
  };

  // ================= ADD COMMENT =================
  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim() || !user) return;

    try {
      const res = await API.post(`/comments/${id}`, {
        body: newComment,
      });

      setComments([res.data, ...comments]);
      setNewComment("");
    } catch (err) {
      setError("Failed to add comment");
    }
  };

  // ================= LOADING =================
  if (loading) return <div className="loading-post">Loading post...</div>;

  if (error)
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        {error}
        <br />
        <button onClick={() => navigate("/")}>Go Home</button>
      </div>
    );

  // ================= OWNER CHECK =================
  const isOwner =
    user && post && user._id === post.author?._id;

  return (
    <section className="single-post-page">
      <div className="post-header">
        <div className="action-buttons">
          <Link to="/create-post" className="nav-btn">
            New Post
          </Link>

          {isOwner && (
            <>
              <Link to={`/edit-post/${id}`} className="nav-btn">
                Edit Post
              </Link>

              <button onClick={handleDeleteClick} className="nav-btn">
                Delete Post
              </button>
            </>
          )}
        </div>
      </div>

      <article className="single-post-card">
        <h2>{post.title}</h2>
        <div className="post-body">{post.body}</div>
      </article>

      {post.image && (
        <div className="post-featured-image">
          <img
            src={`http://localhost:5000/uploads/${post.image}`}
            alt="post"
          />
        </div>
      )}

      {/* ================= DELETE MODAL ================= */}
      {showDeleteConfirm && (
        <div
          onClick={handleDeleteCancel}
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.7)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
          }}
        >
          <div onClick={(e) => e.stopPropagation()}>
            <h3>
              {deleteConfirmType === "post"
                ? "Delete Post?"
                : "Delete Comment?"}
            </h3>

            <button
              onClick={
                deleteConfirmType === "post"
                  ? handleDeleteConfirm
                  : handleDeleteCommentConfirm
              }
            >
              Confirm
            </button>

            <button onClick={handleDeleteCancel}>Cancel</button>
          </div>
        </div>
      )}

      {/* ================= COMMENTS ================= */}
      <section className="comments-section">
        <h3>Comments ({comments.length})</h3>

        {user && (
          <form onSubmit={handleAddComment}>
            <input
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              placeholder="Add comment..."
            />
            <button type="submit">Post</button>
          </form>
        )}

        {comments.map((c) => {
          const isCommentOwner = user && user._id === c.author?._id;

          return (
            <div key={c._id}>
              <strong>{c.author?.name || "User"}</strong>
              <p>{c.body}</p>

              {isCommentOwner && (
                <button onClick={() => handleDeleteCommentClick(c._id)}>
                  Delete
                </button>
              )}
            </div>
          );
        })}
      </section>
    </section>
  );
};

export default PostPage;
